import{d as p,l as d,r as l,o as i,c as v,f as r,b as a,e as t,a as o,i as e,p as u,n as k}from"./app-d6a6dcfa.js";import{_ as f}from"./plugin-vue_export-helper-c27b6911.js";const n=s=>(u("data-v-6406ac90"),s=s(),k(),s),m=n(()=>a("p",null,"На этой странице вы узнаете, как настроить шрифты темы.",-1)),h=e(`<h2 id="семеиство-шрифтов" tabindex="-1" data-v-6406ac90><a class="header-anchor" href="#семеиство-шрифтов" aria-hidden="true" data-v-6406ac90>#</a> Семейство шрифтов</h2><p data-v-6406ac90>Для распространенных семейств шрифтов их обычно можно разделить на <strong data-v-6406ac90>serif</strong><sup class="footnote-ref" data-v-6406ac90><a href="#footnote1" data-v-6406ac90>[1]</a><a class="footnote-anchor" id="footnote-ref1" data-v-6406ac90></a></sup> и <strong data-v-6406ac90>sans-serif</strong><sup class="footnote-ref" data-v-6406ac90><a href="#footnote2" data-v-6406ac90>[2]</a><a class="footnote-anchor" id="footnote-ref2" data-v-6406ac90></a></sup>.</p><h2 id="изменение-шрифтов" tabindex="-1" data-v-6406ac90><a class="header-anchor" href="#изменение-шрифтов" aria-hidden="true" data-v-6406ac90>#</a> Изменение шрифтов</h2><p data-v-6406ac90>Тема предоставляет три переменные <code data-v-6406ac90>$font-family</code>, <code data-v-6406ac90>$font-family-heading</code> и <code data-v-6406ac90>$font-family-mono</code> для управления шрифтом в <code data-v-6406ac90>.vuepress/styles/palette.scss</code>.</p><ul data-v-6406ac90><li data-v-6406ac90><code data-v-6406ac90>$font-family</code>: шрифт, используемый для обычного текста</li><li data-v-6406ac90><code data-v-6406ac90>$font-family-heading:</code> шрифт для элементов заголовков</li><li data-v-6406ac90><code data-v-6406ac90>$font-family-mono</code>: шрифт, используемый в блоке кода и встроенных кодах</li></ul><p data-v-6406ac90>По умолчанию тема использует шрифт без засечек с обычным текстом.</p><div class="hint-container tip" data-v-6406ac90><p class="hint-container-title" data-v-6406ac90>Используйте Serifs</p><p data-v-6406ac90>Если вы предпочитаете шрифты с засечками, вы можете изменить <code data-v-6406ac90>$font-family</code> на нужный вам шрифт.</p><p data-v-6406ac90>Следующие семейства шрифтов являются нашим рекомендуемым первым выбором для шрифтов с засечками:</p><div class="language-scss" data-ext="scss" data-v-6406ac90><pre class="language-scss" data-v-6406ac90><code data-v-6406ac90><span class="token property" data-v-6406ac90><span class="token variable" data-v-6406ac90>$font-family</span></span><span class="token punctuation" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&#39;Georgia, -apple-system, &quot;Nimbus Roman No9 L&quot;, sans-serif&#39;</span><span class="token punctuation" data-v-6406ac90>;</span>
</code></pre></div></div><h2 id="резервныи-шрифт" tabindex="-1" data-v-6406ac90><a class="header-anchor" href="#резервныи-шрифт" aria-hidden="true" data-v-6406ac90>#</a> Резервный шрифт</h2><p data-v-6406ac90>Поскольку разные платформы, разные операционные системы и разные методы установки (тонкая/полная) будут вызывать огромные различия в количестве и типах шрифтов в библиотеке шрифтов, вам следует установить как можно больше шрифтов и убедиться, что резервные шрифты <sup class="footnote-ref" data-v-6406ac90><a href="#footnote3" data-v-6406ac90>[3]</a><a class="footnote-anchor" id="footnote-ref3" data-v-6406ac90></a></sup> существует.</p><div class="hint-container tip" data-v-6406ac90><p class="hint-container-title" data-v-6406ac90>Лучшие практики</p><p data-v-6406ac90>Резервный шрифт <sup class="footnote-ref" data-v-6406ac90><a href="#footnote3" data-v-6406ac90>[3:1]</a><a class="footnote-anchor" id="footnote-ref3:1" data-v-6406ac90></a></sup> может гарантировать, что ваш веб-сайт будет хорошо отображаться в разных операционных системах и на устройствах с установленными разными шрифтами.</p></div><h2 id="библиотека-шрифтов" tabindex="-1" data-v-6406ac90><a class="header-anchor" href="#библиотека-шрифтов" aria-hidden="true" data-v-6406ac90>#</a> Библиотека шрифтов</h2>`,11),g={href:"https://fonts.google.com/",target:"_blank",rel:"noopener noreferrer"},_=e(`<p data-v-6406ac90>Пожалуйста, найдите и выберите нужный шрифт и толщину на веб-странице, затем нажмите кнопку <code data-v-6406ac90>Select</code> справа, чтобы добавить его в список выбора, затем нажмите кнопку в правом верхнем углу, чтобы просмотреть ваши любимые шрифты и получить ссылку Импортируется в файл конфигурации VuePress.</p><p data-v-6406ac90>Мы предполагаем, что вы выбрали курсив 400 и 700 шрифта Lora. После нажатия кнопки в правом верхнем углу Google выдаст в сайдбаре следующий код:</p><div class="language-html" data-ext="html" data-v-6406ac90><pre class="language-html" data-v-6406ac90><code data-v-6406ac90><span class="token tag" data-v-6406ac90><span class="token tag" data-v-6406ac90><span class="token punctuation" data-v-6406ac90>&lt;</span>link</span> <span class="token attr-name" data-v-6406ac90>rel</span><span class="token attr-value" data-v-6406ac90><span class="token punctuation attr-equals" data-v-6406ac90>=</span><span class="token punctuation" data-v-6406ac90>&quot;</span>preconnect<span class="token punctuation" data-v-6406ac90>&quot;</span></span> <span class="token attr-name" data-v-6406ac90>href</span><span class="token attr-value" data-v-6406ac90><span class="token punctuation attr-equals" data-v-6406ac90>=</span><span class="token punctuation" data-v-6406ac90>&quot;</span>https://fonts.googleapis.com<span class="token punctuation" data-v-6406ac90>&quot;</span></span> <span class="token punctuation" data-v-6406ac90>/&gt;</span></span>
<span class="token tag" data-v-6406ac90><span class="token tag" data-v-6406ac90><span class="token punctuation" data-v-6406ac90>&lt;</span>link</span> <span class="token attr-name" data-v-6406ac90>rel</span><span class="token attr-value" data-v-6406ac90><span class="token punctuation attr-equals" data-v-6406ac90>=</span><span class="token punctuation" data-v-6406ac90>&quot;</span>preconnect<span class="token punctuation" data-v-6406ac90>&quot;</span></span> <span class="token attr-name" data-v-6406ac90>href</span><span class="token attr-value" data-v-6406ac90><span class="token punctuation attr-equals" data-v-6406ac90>=</span><span class="token punctuation" data-v-6406ac90>&quot;</span>https://fonts.gstatic.com<span class="token punctuation" data-v-6406ac90>&quot;</span></span> <span class="token attr-name" data-v-6406ac90>crossorigin</span> <span class="token punctuation" data-v-6406ac90>/&gt;</span></span>
<span class="token tag" data-v-6406ac90><span class="token tag" data-v-6406ac90><span class="token punctuation" data-v-6406ac90>&lt;</span>link</span>
  <span class="token attr-name" data-v-6406ac90>href</span><span class="token attr-value" data-v-6406ac90><span class="token punctuation attr-equals" data-v-6406ac90>=</span><span class="token punctuation" data-v-6406ac90>&quot;</span>https://fonts.googleapis.com/css2?family=Lora:ital,wght@0,400;1,700&amp;display=swap<span class="token punctuation" data-v-6406ac90>&quot;</span></span>
  <span class="token attr-name" data-v-6406ac90>rel</span><span class="token attr-value" data-v-6406ac90><span class="token punctuation attr-equals" data-v-6406ac90>=</span><span class="token punctuation" data-v-6406ac90>&quot;</span>stylesheet<span class="token punctuation" data-v-6406ac90>&quot;</span></span>
<span class="token punctuation" data-v-6406ac90>/&gt;</span></span>
</code></pre></div><div class="language-css" data-ext="css" data-v-6406ac90><pre class="language-css" data-v-6406ac90><code data-v-6406ac90><span class="token property" data-v-6406ac90>font-family</span><span class="token punctuation" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;Lora&quot;</span><span class="token punctuation" data-v-6406ac90>,</span> serif<span class="token punctuation" data-v-6406ac90>;</span>
</code></pre></div><p data-v-6406ac90>Затем все, что вам нужно сделать, это импортировать и использовать их, добавив следующий код в файл конфигурации VuePress:</p><div class="language-typescript line-numbers-mode" data-ext="ts" data-v-6406ac90><pre class="language-typescript" data-v-6406ac90><code data-v-6406ac90><span class="token comment" data-v-6406ac90>// .vuepress/config.ts</span>
<span class="token keyword" data-v-6406ac90>import</span> <span class="token punctuation" data-v-6406ac90>{</span> defineUserConfig <span class="token punctuation" data-v-6406ac90>}</span> <span class="token keyword" data-v-6406ac90>from</span> <span class="token string" data-v-6406ac90>&quot;vuepress&quot;</span><span class="token punctuation" data-v-6406ac90>;</span>

<span class="token keyword" data-v-6406ac90>export</span> <span class="token keyword" data-v-6406ac90>default</span> <span class="token function" data-v-6406ac90>defineUserConfig</span><span class="token punctuation" data-v-6406ac90>(</span><span class="token punctuation" data-v-6406ac90>{</span>
  <span class="token comment" data-v-6406ac90>//...</span>

  head<span class="token operator" data-v-6406ac90>:</span> <span class="token punctuation" data-v-6406ac90>[</span>
    <span class="token comment" data-v-6406ac90>//...</span>

    <span class="token comment" data-v-6406ac90>// Import the corresponding link</span>
    <span class="token punctuation" data-v-6406ac90>[</span><span class="token string" data-v-6406ac90>&quot;link&quot;</span><span class="token punctuation" data-v-6406ac90>,</span> <span class="token punctuation" data-v-6406ac90>{</span> rel<span class="token operator" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;preconnect&quot;</span><span class="token punctuation" data-v-6406ac90>,</span> href<span class="token operator" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;https://fonts.googleapis.com&quot;</span> <span class="token punctuation" data-v-6406ac90>}</span><span class="token punctuation" data-v-6406ac90>]</span><span class="token punctuation" data-v-6406ac90>,</span>
    <span class="token punctuation" data-v-6406ac90>[</span>
      <span class="token string" data-v-6406ac90>&quot;link&quot;</span><span class="token punctuation" data-v-6406ac90>,</span>
      <span class="token punctuation" data-v-6406ac90>{</span> rel<span class="token operator" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;preconnect&quot;</span><span class="token punctuation" data-v-6406ac90>,</span> href<span class="token operator" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;https://fonts.gstatic.com&quot;</span><span class="token punctuation" data-v-6406ac90>,</span> crossorigin<span class="token operator" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;&quot;</span> <span class="token punctuation" data-v-6406ac90>}</span><span class="token punctuation" data-v-6406ac90>,</span>
    <span class="token punctuation" data-v-6406ac90>]</span><span class="token punctuation" data-v-6406ac90>,</span>
    <span class="token punctuation" data-v-6406ac90>[</span>
      <span class="token string" data-v-6406ac90>&quot;link&quot;</span><span class="token punctuation" data-v-6406ac90>,</span>
      <span class="token punctuation" data-v-6406ac90>{</span>
        href<span class="token operator" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@400;500;700&amp;display=swap&quot;</span><span class="token punctuation" data-v-6406ac90>,</span>
        rel<span class="token operator" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;stylesheet&quot;</span><span class="token punctuation" data-v-6406ac90>,</span>
      <span class="token punctuation" data-v-6406ac90>}</span><span class="token punctuation" data-v-6406ac90>,</span>
    <span class="token punctuation" data-v-6406ac90>]</span><span class="token punctuation" data-v-6406ac90>,</span>
  <span class="token punctuation" data-v-6406ac90>]</span><span class="token punctuation" data-v-6406ac90>,</span>

  <span class="token comment" data-v-6406ac90>//...</span>
<span class="token punctuation" data-v-6406ac90>}</span><span class="token punctuation" data-v-6406ac90>)</span><span class="token punctuation" data-v-6406ac90>;</span>
</code></pre><div class="line-numbers" aria-hidden="true" data-v-6406ac90><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div><div class="line-number" data-v-6406ac90></div></div></div><p data-v-6406ac90>Также измените переменную <code data-v-6406ac90>$font-family</code> в файле палитры:</p><div class="language-scss" data-ext="scss" data-v-6406ac90><pre class="language-scss" data-v-6406ac90><code data-v-6406ac90><span class="token comment" data-v-6406ac90>// .vuepress/styles/palette.scss</span>

<span class="token comment" data-v-6406ac90>// apply font</span>
<span class="token property" data-v-6406ac90><span class="token variable" data-v-6406ac90>$font-family</span></span><span class="token punctuation" data-v-6406ac90>:</span> <span class="token string" data-v-6406ac90>&quot;Lora, serif&quot;</span><span class="token punctuation" data-v-6406ac90>;</span>
</code></pre></div><p data-v-6406ac90>Таким образом, вы можете использовать шрифт lora на своем веб-сайте.</p><details class="hint-container details" data-v-6406ac90><summary data-v-6406ac90>lora Демо</summary><!-- markdownlint-disable MD033 --><div class="lora" data-v-6406ac90><h2 id="принимая-во-внимание-что-признание-присущего-достоинству" tabindex="-1" data-v-6406ac90><a class="header-anchor" href="#принимая-во-внимание-что-признание-присущего-достоинству" aria-hidden="true" data-v-6406ac90>#</a> Принимая во внимание, что признание присущего достоинству</h2><p data-v-6406ac90>Никто не может быть подвергнут произвольному аресту, задержанию или ссылки.<br data-v-6406ac90> Каждый имеет право на полное равенство на справедливое и публичное разбирательство дела независимым и беспристрастным судом при рассмотрении его прав и обязанностей и любого уголовного обвинения против него.<br data-v-6406ac90> Никто не может подвергаться произвольному вмешательству в его частную жизнь, семью, жилище или переписку, а также посягательствам на его честь и репутацию. Каждый имеет право на защиту закона от такого вмешательства или посягательств.</p></div><!-- markdownlint-enable MD033 --></details><hr class="footnotes-sep" data-v-6406ac90>`,11),b={class:"footnotes"},q={class:"footnotes-list"},y={id:"footnote1",class:"footnote-item"},w={href:"https://www.zhihu.com/topic/19559432/intro",target:"_blank",rel:"noopener noreferrer"},x=n(()=>a("a",{href:"#footnote-ref1",class:"footnote-backref"},"↩︎",-1)),S={id:"footnote2",class:"footnote-item"},$={href:"https://www.zhihu.com/topic/19559433/intro",target:"_blank",rel:"noopener noreferrer"},N=n(()=>a("a",{href:"#footnote-ref2",class:"footnote-backref"},"↩︎",-1)),C=n(()=>a("li",{id:"footnote3",class:"footnote-item"},[a("p",null,"Из Википедии"),a("p",null,"Резервные шрифты — это шрифты, которые используются для отображения отсутствующих символов, когда в отображаемом шрифте отсутствуют определенные символы. Поскольку он служит последней линией защиты для отображения, резервные шрифты должны по возможности содержать все символы Юникода."),a("p",null,[t("Если отсутствующий символ не имеет резервного шрифта для отображения, отсутствующий символ обычно отображается в виде черного квадрата, белого пустого квадрата, вопросительного знака, заполнителя Unicode (U+FFFD) или просто пропускается. На практике такие системы, как CSS, которые поддерживают последовательное отображение списков шрифтов, обычно помещают один или несколько наборов резервных шрифтов в конец списка, чтобы предотвратить пропущенные символы. "),a("a",{href:"#footnote-ref3",class:"footnote-backref"},"↩︎"),t(),a("a",{href:"#footnote-ref3:1",class:"footnote-backref"},"↩︎")])],-1)),I=p({__name:"font.html",setup(s){return d("https://fonts.googleapis.com/css2?family=Noto+Serif+SC:wght@600;900&display=swap"),(L,V)=>{const c=l("ExternalLinkIcon");return i(),v("div",null,[m,r(" more "),h,a("p",null,[t("Вы можете найти больше шрифтов в "),a("a",g,[t("Google Fonts"),o(c)]),t(", а также просмотреть и загрузить их онлайн.")]),_,a("section",b,[a("ol",q,[a("li",y,[a("p",null,[t("Связанное введение: "),a("a",w,[t("https://www.zhihu.com/topic/19559432/intro"),o(c)]),t(),x])]),a("li",S,[a("p",null,[t("Связанное введение: "),a("a",$,[t("https://www.zhihu.com/topic/19559433/intro"),o(c)]),t(),N])]),C])])])}}});const U=f(I,[["__scopeId","data-v-6406ac90"],["__file","font.html.vue"]]);export{U as default};
